-- DESACTIVADO (2026-07-20, bug real encontrado: "el export no esta guardando
-- esos datos" -- este bloque volvia a sobrescribir ns.BUILTIN.units/portraits/
-- etc CADA carga con el snapshot VIEJO embebido arriba en ns.ProfExports.myaddon
-- -- ese snapshot es de ANTES de que existieran las unidades de arena/raid, asi
-- que las borraba silenciosamente en cada login, sin ningun error de Lua.
-- Defaults.lua (cargado antes en el .toc) es ahora la UNICA fuente de verdad de
-- ns.BUILTIN; este bloque queda documentado pero inerte).
if false then
    local str = ns.ProfExports.myaddon
    if type(str) == "string" and str ~= "" then
        local body = str:gsub("^%s+", ""):gsub("%s+$", ""):gsub("^MCF1:%s*", "")
        local loader = loadstring or load
        local f = body ~= "" and loader("return " .. body, "mcf_builtin")
        if f then
            if setfenv then setfenv(f, {}) end
            local ok, data = pcall(f)
            if ok and type(data) == "table" and type(data.units) == "table" then
                ns.BUILTIN = ns.BUILTIN or {}
                ns.BUILTIN.units      = data.units
                ns.BUILTIN.portraits  = data.portraits
                ns.BUILTIN.auras      = data.auras
                ns.BUILTIN.infobar    = data.infobar
                ns.BUILTIN.micromenu  = data.micromenu
                ns.BUILTIN.chatbubble = data.chatbubble
                ns.BUILTIN.glow       = data.glow
                ns.BUILTIN.tracker    = data.tracker
                if type(data.globals) == "table" then
                    for k, v in pairs(data.globals) do ns.BUILTIN[k] = v end
                end
            end
        end
    end
end
